#include<bits/stdc++.h>
using namespace std;
long long n,fa[200010][21],val[200010];
long long l,dis[200010];
int main()
{
    scanf("%lld%lld",&n,&l);
    fa[1][0]=1;
    for(long long i=2;i<=n;i++)
    {
        scanf("%lld",&fa[i][0]);
        long long x;
        scanf("%lld",&x);
        dis[i]=dis[fa[i][0]]+x;
        for(long long j=1;j<=19;j++)
        {
            fa[i][j]=fa[fa[i][j-1]][j-1];
        }
    }
    for(long long i=1;i<=n;i++)
    {
        long long x=i;
        val[x]++;
        long long tmp=l;
        for(long long i=19;i>=0;i--)
        {
            if(dis[x]-dis[fa[x][i]]<=tmp)
            {
                tmp-=dis[x]-dis[fa[x][i]];
                x=fa[x][i];
            }
        }
        if(x!=1)
        {
            val[fa[x][0]]--;
        }
    }
    for(long long i=n;i>=2;i--)
    {
        val[fa[i][0]]+=val[i];
    }
    for(long long i=1;i<=n;i++)
    {
        printf("%lld\n",val[i]);
    }
    return 0;
}
